function mapCategory(tags) {
  if (!tags) return null;
  const { amenity, shop, advertising } = tags;
  if (amenity === 'fuel') return 'fuel_station';
  if (amenity === 'pharmacy') return 'pharmacy';
  if (amenity === 'money_transfer' || amenity === 'mobile_money') return 'mobile_money';
  if (shop === 'mobile_phone') return 'mobile_money';
  if (shop === 'alcohol' || amenity === 'bar' || amenity === 'pub') return 'alcohol_outlet';
  if (advertising === 'billboard' || advertising === 'board') return 'billboard';
  return null;
}

const elements = Array.isArray($json.elements) ? $json.elements : [];
const leads = elements
  .filter(item => item.lat != null && item.lon != null && item.id != null)
  .map(item => {
    const category = mapCategory(item.tags);
    if (!category) return null;
    const amenity = item.tags?.amenity;
    return {
      sourceRecordId: `osm:${item.id}`,
      sourceUrl: `https://www.openstreetmap.org/node/${item.id}`,
      category,
      location: {
        latitude: Number(item.lat),
        longitude: Number(item.lon),
      },
      normalizedDetails: {
        name: item.tags?.name ?? null,
        brand: item.tags?.brand ?? null,
        operator: item.tags?.operator ?? null,
      },
      rawPayload: item,
      evidenceUrls: [`https://www.openstreetmap.org/node/${item.id}`],
      freshnessAt: new Date().toISOString(),
      priority: (amenity === 'fuel' || amenity === 'pharmacy') ? 'high' : 'medium',
    };
  })
  .filter(Boolean);

if (leads.length === 0) {
  throw new Error('Overpass returned 0 mappable nodes — check bbox and query tags');
}

const run = $('Set Run Metadata').first().json;
return [{ json: { ...run, completedAt: new Date().toISOString(), leads } }];
